#include<bits/stdc++.h>
using namespace std;
long long n,l,d[1000010],s[1000010],w[1000010];
long long x(long long v)
{
    return s[v];
}
long long y(long long v)
{
    return d[v]*s[v];
}
long long k(long long v)
{
    return d[v];
}
double xielv(long long i,long long j)
{
    return 1.0*(y(i)-y(j))/(x(i)-x(j));
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&w[i],&d[i],&x);
    }
    for(long long i=n;i>=1;i--)
    {
        d[i]+=d[i+1];
    }
    long long sum=0;
    for(int i=1;i<=n;i++)
    {
        s[i]=s[i-1]+w[i];
        sum+=d[i]*w[i];
    }
    deque<long long> q;
    q.push_back(0);
    long long ans=LLONG_MAX;
    for(long long i=1;i<=n;i++)
    {
        while(q.size()>=2&&xielv(q[0],q[1])>k(i))
        {
            q.pop_front();
        }
        ans=min(ans,sum-y(q[0])-d[i]*(s[i]-s[q[0]]));
        while(q.size()>=2&&xielv(q[q.size()-2],q[q.size()-1])<xielv(q[q.size()-1],i))
        {
            q.pop_back();
        }
        q.push_back(i);
    }
    printf("%lld",ans);
    return 0;
}
